private void annotateCalls(Node n) {
  Preconditions.checkState(n.isCall());

  // Keep track of of the 'this' context of a call.  A call without an
  // explicit 'this' is a free call.
  Node first = n.getFirstChild();

  // Ignore cast nodes and properly determine free calls without explicit 'this'.
  if (first.isName() && n.getParent() != null && n.getParent().isGetProp()) {
    n.putBooleanProp(Node.FREE_CALL, false);
  } else {
    n.putBooleanProp(Node.FREE_CALL, true);
  }

  // Keep track of the context in which eval is called. It is important
  // to distinguish between '(0, eval)()' and 'eval()'.
  if (first.isName() &&
      "eval".equals(first.getString())) {
    first.putBooleanProp(Node.DIRECT_EVAL, true);
  }
}

private void annotateCalls(Node n) {
  Preconditions.checkState(n.isCall());

  Node first = n.getFirstChild();

  // A call is 'free' if it doesn't have an explicit 'this'.
  // It should be a direct name or literal (e.g., 'foo()' or '"baz"()'),
  // indicating no call chain.
  if (first.isName() || first.isString()) {
    n.putBooleanProp(Node.FREE_CALL, true);
  }

  // Check if the call is a direct eval call.
  if (first.isName() && "eval".equals(first.getString())) {
    first.putBooleanProp(Node.DIRECT_EVAL, true);
  }
}

